INSERT INTO `menus` VALUES (1,'아메리카노',3000,'커피','Deep and rich espresso with water',1,'2026-04-23 09:00:43'),(2,'라떼',4000,'커피',NULL,1,'2026-04-23 09:00:44'),(3,'딸기스무디',5500,'스무디',NULL,1,'2026-04-23 09:00:44'),(4,'녹차',3500,'차',NULL,1,'2026-04-23 09:00:44'),(5,'바닐라 라떼',5000,'커피',NULL,0,'2026-04-23 09:02:09'),(6,'아메리카노',3500,'커피','깊고 진한 에스프레소에 물을 더해 부드럽게 즐기는 대표 블랙커피',1,'2026-04-24 01:04:21'),(7,'카페라떼',4500,'커피','진한 에스프레소와 신선한 우유의 완벽한 조화',1,'2026-04-24 01:04:21'),(8,'카푸치노',4500,'커피','풍성한 우유 거품과 에스프레소의 클래식한 만남',1,'2026-04-24 01:04:21'),(9,'바닐라라떼',5000,'커피','달콤한 바닐라 시럽과 부드러운 우유폼이 어우러진 인기 메뉴',1,'2026-04-24 01:04:21'),(10,'카라멜마키아토',5500,'커피','에스프레소 위에 카라멜 드리즐을 더한 달콤한 프리미엄',1,'2026-04-24 01:04:21'),(11,'콜드브루',5000,'커피','12시간 저온 추출로 만든 부드럽고 깊은 풍미의 커피',1,'2026-04-24 01:04:21'),(12,'에스프레소',3000,'커피','이탈리아식 정통 에스프레소. 진하고 강렬한 한 모금',1,'2026-04-24 01:04:21'),(13,'녹차라떼',5000,'라떼','제주산 말차 파우더로 만든 진하고 향긋한 그린 라떼',1,'2026-04-24 01:04:21'),(14,'딸기라떼',5500,'라떼','상큼한 딸기와 우유의 달콤한 조합, 눈도 입도 행복한 라떼',1,'2026-04-24 01:04:21'),(15,'초코라떼',5000,'라떼','벨기에산 다크 초콜릿과 스팀밀크로 만든 진한 초코 음료',1,'2026-04-24 01:04:21'),(16,'흑임자라떼',5500,'라떼','고소한 흑임자와 우유가 어우러진 한국식 웰니스 라떼',1,'2026-04-24 01:04:21'),(17,'자몽에이드',5500,'에이드','상큼한 자몽과 탄산의 청량한 조합. 무더운 날의 필수템',1,'2026-04-24 01:04:21'),(18,'레몬에이드',5000,'에이드','신선한 레몬즙과 탄산수의 깔끔하고 산뜻한 에이드',1,'2026-04-24 01:04:21'),(19,'딸기스무디',6000,'스무디','신선한 딸기와 요거트를 갈아 만든 달콤 상큼 스무디',1,'2026-04-24 01:04:21'),(20,'망고스무디',6000,'스무디','달콤한 망고과육 가득, 열대의 맛을 한 잔에 담았어요',1,'2026-04-24 01:04:21'),(21,'녹차',4000,'차','국내산 녹차잎으로 우린 깔끔하고 건강한 한 잔',1,'2026-04-24 01:04:21'),(22,'캐모마일',4000,'차','부드럽고 은은한 향의 허브티. 릴랙스가 필요할 때',1,'2026-04-24 01:04:21'),(23,'유자차',4500,'차','향긋한 유자향과 은은한 꿀의 달콤함이 가득한 전통 차',1,'2026-04-24 01:04:21');
